	.TITLE	T64	.PROC	M680002	.REF	SMAKY	.REF	MODULESLBNUM	=	LGCHUS64	.LOC	0OCHMATH:.BLKB	2OBNUM1:	.BLKB	LBNUMOBNUM2:	.BLKB	LBNUMOBNUMR:	.BLKB	LBNUM+10LGVAR:	.LOC	0START:	LOAD.L	A6,#R16"VAR	LOAD.L	A3,#R16"NMMATH	LOAD.W	D3,#MATH64_FIRST	LIB_	OPEN	JUMP,NE ERROR	LOAD.W	(A6)+OCHMATH,D1	LOAD.L	D0,#2^BM64C7D	; D0 <-- mode par dfaut	MATH64_	OPEN	JUMP,NE ERRORLOOP:	LIB	?AFTIM	.ASCIZ	"Premier nombre = "	.EVEN	LOAD.L	A3,#(A6)+OBNUM1	LOAD.W	D3,#LBNUM	LIB	?GETLINE	COMP.W	D3,#END	JUMP,EQ FIN	LOAD.L	A3,#(A6)+OBNUM1	MATH64_	ASC_FP	LIB	?AFTIM	.ASCIZ	"Rsultat = "	.EVEN	LOAD.L	A3,#(A6)+OBNUM1	LOAD.L	D0,#2^BM64POW!2^BM64CDRT;;?	LOAD.B	D0,(A6)+OGRADL+1 ; D0 <-- nb total de signesLOAD.B D0,#4	SWAP.W	D0;;?	LOAD.B	D0,(A6)+OGRADN+1 ; D0 <-- nb de dcimalesLOAD.B D0,#1	NEG.B	D0	SWAP.W	D0	MATH64_	FP_ASC	LIB	?AFTEXT	LIB	?AFCR	LIB	?AFCR	JUMP	LOOPERROR:	LIB	?AFERRORFIN:	MATH64_	CLOSE	LOAD.W	D1,(A6)+OCHMATH	LIB_	CLOSE	EXITNMMATH:	.ASCIZ	"MATH64"	.EVENVAR:	.FILLB	LGVAR,0	.END	START